```class Solution {
public:
    string reverseOnlyLetters(string s) {
        string res = "";
        for(int i = 0, j = s.length() - 1; i <= j; i++, j--) {
            if(!isalpha(s[i])) {
                res += s[i];
            } else if(!isalpha(s[j])) {
                res += s[j];
                j--;
            } else {
                res += s[j];
                j--;
                res += s[i];
                i++;
            }
        }
        return res;
    }
};```
